import {
  Work as WorkIcon,
  Schedule as ScheduleIcon,
  CheckCircle as CheckCircleIcon,
  Pending as PendingIcon,
  Cancel as CancelIcon,
  Person as PersonIcon,
  Email as EmailIcon,
  Phone as PhoneIcon,
  LocationOn as LocationIcon,
  School as SchoolIcon,
  Business as BusinessIcon,
  Description as DescriptionIcon,
  Edit as EditIcon,
  Assessment as AssessmentIcon,
  VideoCall as VideoCallIcon,
  CalendarToday as CalendarIcon,
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

interface Application {
  id: string;
  jobId: string;
  jobTitle: string;
  company: string;
  status: 'pending' | 'reviewing' | 'interview' | 'accepted' | 'rejected';
  appliedDate: string;
  interviewDate?: string;
  interviewType?: 'video' | 'in-person';
  interviewStatus?: 'scheduled' | 'completed' | 'cancelled';
}

interface Profile {
  name: string;
  email: string;
  phone: string;
  location: string;
  education: Array<{
    degree: string;
    institution: string;
    year: string;
  }>;
  experience: Array<{
    title: string;
    company: string;
    duration: string;
  }>;
  skills: string[];
  resume: string;
}

const ApplicantDashboard: React.FC = () => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState(0);
  const [applications, setApplications] = useState<Application[]>([]);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        // Fetch applications and profile data
        const [applicationsRes, profileRes] = await Promise.all([
          axios.get('/api/applications'),
          axios.get('/api/profile')
        ]);
        setApplications(applicationsRes.data);
        setProfile(profileRes.data);
      } catch (err) {
        setError('Failed to load dashboard data');
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  const handleTabChange = (event: React.SyntheticEvent, newValue: number) => {
    setActiveTab(newValue);
  };

  const getStatusChip = (status: Application['status']) => {
    const statusConfig = {
      pending: { color: 'warning', icon: <PendingIcon /> },
      reviewing: { color: 'info', icon: <ScheduleIcon /> },
      interview: { color: 'primary', icon: <VideoCallIcon /> },
      accepted: { color: 'success', icon: <CheckCircleIcon /> },
      rejected: { color: 'error', icon: <CancelIcon /> },
    };

    const config = statusConfig[status];
    return (
      <Chip
        icon={config.icon}
        label={status.charAt(0).toUpperCase() + status.slice(1)}
        color={config.color as any}
        size="small"
      />
    );
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Container maxWidth="lg" sx={{ py: 4 }}>
        <Alert severity="error">{error}</Alert>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <Grid container spacing={4}>
        {/* Profile Section */}
        <Grid item xs={12} md={4}>
          <Paper elevation={3} sx={{ p: 3, borderRadius: 2 }}>
            <Box display="flex" alignItems="center" mb={3}>
              <Avatar sx={{ width: 80, height: 80, mr: 2 }} />
              <Box>
                <Typography variant="h5">{profile?.name}</Typography>
                <Typography variant="body2" color="text.secondary">
                  {profile?.email}
                </Typography>
              </Box>
            </Box>

            <List>
              <ListItem>
                <ListItemIcon>
                  <EmailIcon color="primary" />
                </ListItemIcon>
                <ListItemText primary="Email" secondary={profile?.email} />
              </ListItem>
              <ListItem>
                <ListItemIcon>
                  <PhoneIcon color="primary" />
                </ListItemIcon>
                <ListItemText primary="Phone" secondary={profile?.phone} />
              </ListItem>
              <ListItem>
                <ListItemIcon>
                  <LocationIcon color="primary" />
                </ListItemIcon>
                <ListItemText primary="Location" secondary={profile?.location} />
              </ListItem>
            </List>

            <Button
              variant="outlined"
              startIcon={<EditIcon />}
              fullWidth
              onClick={() => navigate('/profile/edit')}
            >
              Edit Profile
            </Button>
          </Paper>

          {/* Skills Section */}
          <Paper elevation={3} sx={{ p: 3, borderRadius: 2, mt: 3 }}>
            <Typography variant="h6" gutterBottom>
              Skills
            </Typography>
            <Box display="flex" flexWrap="wrap" gap={1}>
              {profile?.skills.map((skill, index) => (
                <Chip key={index} label={skill} />
              ))}
            </Box>
          </Paper>
        </Grid>

        {/* Main Content */}
        <Grid item xs={12} md={8}>
          <Paper elevation={3} sx={{ p: 3, borderRadius: 2 }}>
            <Tabs value={activeTab} onChange={handleTabChange} sx={{ mb: 3 }}>
              <Tab label="Applications" />
              <Tab label="Interviews" />
              <Tab label="Profile" />
            </Tabs>

            {/* Applications Tab */}
            {activeTab === 0 && (
              <Box>
                <Typography variant="h6" gutterBottom>
                  Your Applications
                </Typography>
                {applications.length === 0 ? (
                  <Alert severity="info">You haven't applied to any jobs yet.</Alert>
                ) : (
                  <List>
                    {applications.map((application) => (
                      <React.Fragment key={application.id}>
                        <ListItem>
                          <ListItemIcon>
                            <WorkIcon color="primary" />
                          </ListItemIcon>
                          <ListItemText
                            primary={
                              <Box display="flex" alignItems="center" gap={1}>
                                <Typography variant="subtitle1">
                                  {application.jobTitle}
                                </Typography>
                                {getStatusChip(application.status)}
                              </Box>
                            }
                            secondary={
                              <>
                                <Typography variant="body2">
                                  {application.company}
                                </Typography>
                                <Typography variant="caption" color="text.secondary">
                                  Applied on {new Date(application.appliedDate).toLocaleDateString()}
                                </Typography>
                              </>
                            }
                          />
                          <Button
                            variant="outlined"
                            size="small"
                            onClick={() => navigate(`/jobs/${application.jobId}`)}
                          >
                            View Details
                          </Button>
                        </ListItem>
                        <Divider />
                      </React.Fragment>
                    ))}
                  </List>
                )}
              </Box>
            )}

            {/* Interviews Tab */}
            {activeTab === 1 && (
              <Box>
                <Typography variant="h6" gutterBottom>
                  Upcoming Interviews
                </Typography>
                {applications.filter(app => app.interviewDate).length === 0 ? (
                  <Alert severity="info">No upcoming interviews scheduled.</Alert>
                ) : (
                  <List>
                    {applications
                      .filter(app => app.interviewDate)
                      .map((application) => (
                        <Card key={application.id} sx={{ mb: 2 }}>
                          <CardContent>
                            <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
                              <Typography variant="h6">{application.jobTitle}</Typography>
                              <Chip
                                icon={application.interviewType === 'video' ? <VideoCallIcon /> : <BusinessIcon />}
                                label={application.interviewType}
                                color="primary"
                                size="small"
                              />
                            </Box>
                            <Typography variant="body2" color="text.secondary" gutterBottom>
                              {application.company}
                            </Typography>
                            <Box display="flex" alignItems="center" gap={1} mb={2}>
                              <CalendarIcon fontSize="small" />
                              <Typography variant="body2">
                                {new Date(application.interviewDate!).toLocaleString()}
                              </Typography>
                            </Box>
                            <Button
                              variant="contained"
                              startIcon={<VideoCallIcon />}
                              onClick={() => navigate(`/interview/${application.id}`)}
                            >
                              Join Interview
                            </Button>
                          </CardContent>
                        </Card>
                      ))}
                  </List>
                )}
              </Box>
            )}

            {/* Profile Tab */}
            {activeTab === 2 && (
              <Box>
                <Typography variant="h6" gutterBottom>
                  Education
                </Typography>
                <List>
                  {profile?.education.map((edu, index) => (
                    <ListItem key={index}>
                      <ListItemIcon>
                        <SchoolIcon color="primary" />
                      </ListItemIcon>
                      <ListItemText
                        primary={edu.degree}
                        secondary={`${edu.institution} (${edu.year})`}
                      />
                    </ListItem>
                  ))}
                </List>

                <Typography variant="h6" gutterBottom sx={{ mt: 3 }}>
                  Experience
                </Typography>
                <List>
                  {profile?.experience.map((exp, index) => (
                    <ListItem key={index}>
                      <ListItemIcon>
                        <BusinessIcon color="primary" />
                      </ListItemIcon>
                      <ListItemText
                        primary={exp.title}
                        secondary={`${exp.company} (${exp.duration})`}
                      />
                    </ListItem>
                  ))}
                </List>

                <Box mt={3}>
                  <Button
                    variant="outlined"
                    startIcon={<DescriptionIcon />}
                    onClick={() => window.open(profile?.resume, '_blank')}
                  >
                    View Resume
                  </Button>
                </Box>
              </Box>
            )}
          </Paper>
        </Grid>
      </Grid>
    </Container>
  );
};

export default ApplicantDashboard;
